14	class OrderController extends Controller
15	{
16	    public function store(Request $request): JsonResponse
17	    {
18	        $request->validate([
19	            'cart_id' => 'required|integer',
20	        ]);
21	
22	        // Verify the caller owns this cart (bound to their server session)
23	        $cart = \Illuminate\Support\Facades\DB::table('carts')
24	            ->where('id', (int) $request->input('cart_id'))
25	            ->first();
26	
27	        if (!$cart || $cart->session_id !== session()->getId()) {
28	            return response()->json(['message' => 'Cart not found or access denied.'], 403);
29	        }
30	
31	        $useCase = new CreateOrderUseCase();
32	        $order = $useCase->execute((int) $request->input('cart_id'));
33	
34	        return response()->json([
35	            'data' => $order,
36	            'tracking_url' => url("/order/{$order['tracking_token']}"),
37	        ], 201);
38	    }
39	
40	    public function show(string $trackingToken): JsonResponse
41	    {
42	        $order = DB::table('orders')
43	            ->where('tracking_token', $trackingToken)
44	            ->first();
45	
46	        if (!$order) {
47	            return response()->json(['message' => 'Order not found.'], 404);
48	        }
49	
50	        $items = DB::table('order_items')
51	            ->where('order_id', $order->id)
52	            ->get()
53	            ->map(fn ($item) => (array) $item);
54	
55	        $statusLog = DB::table('order_status_logs')
56	            ->where('order_id', $order->id)
57	            ->orderBy('created_at', 'desc')
58	            ->get()
59	            ->map(fn ($log) => (array) $log);
60	
61	        return response()->json([
62	            'data' => (array) $order,
63	            'items' => $items,
64	            'status_log' => $statusLog,
65	        ]);
66	    }
67	
68	    public function transition(Request $request, int $orderId): JsonResponse
69	    {
70	        $request->validate([
71	            'target_status' => 'required|string|in:pending_confirmation,in_preparation,served,settled,canceled',
72	            'expected_version' => 'required|integer',
73	            'manager_pin' => 'nullable|string',
74	            'cancel_reason' => 'nullable|string',
75	        ]);
76	
77	        $user = $request->user();
78	        $managerPinHash = null;
79	        if ($request->input('manager_pin') && $user->manager_pin) {
80	            $managerPinHash = $user->manager_pin;
81	        }
82	
83	        $useCase = app(TransitionOrderUseCase::class);
84	        $order = $useCase->execute(
85	            orderId: $orderId,
86	            targetStatus: $request->input('target_status'),
87	            expectedVersion: (int) $request->input('expected_version'),
88	            actorRole: $user->role,
89	            actorId: $user->id,
90	            managerPin: $request->input('manager_pin'),
91	            managerPinHash: $managerPinHash,
92	            cancelReason: $request->input('cancel_reason'),
93	        );
94	
95	        return response()->json(['data' => $order]);
96	    }
97	
98	    public function applyDiscount(Request $request, int $orderId): JsonResponse
99	    {
100	        $request->validate([
101	            'amount' => 'required|numeric|min:0.01',
102	            'expected_version' => 'required|integer',
103	            'manager_pin' => 'nullable|string',
104	            'reason' => 'nullable|string',
105	        ]);
106	
107	        $user = $request->user();
108	        $amount = round((float) $request->input('amount'), 2);
109	
110	        $verifier = app(\App\Domain\Auth\StepUpVerifier::class);
111	        if ($verifier->requiresStepUp('discount_override', ['discount_amount' => $amount])) {
112	            if (!$request->input('manager_pin') || !$user->manager_pin) {
113	                return response()->json([
114	                    'message' => 'Manager PIN required for discounts over $20.00.',
115	                    'error_code' => 'STEP_UP_REQUIRED',
116	                ], 403);
117	            }
118	            if (!$verifier->verify($request->input('manager_pin'), $user->manager_pin)) {
119	                return response()->json([
120	                    'message' => 'Incorrect manager PIN.',
121	                    'error_code' => 'STEP_UP_FAILED',
122	                ], 403);
123	            }
124	        }
125	
126	        $expectedVersion = (int) $request->input('expected_version');
127	
128	        // Atomic compare-and-swap inside transaction to prevent lost updates
129	        return DB::transaction(function () use ($orderId, $amount, $expectedVersion, $user, $request) {
130	            $order = DB::table('orders')->where('id', $orderId)->lockForUpdate()->first();
131	
132	            if (!$order) {
133	                return response()->json(['message' => 'Order not found.'], 404);
134	            }
135	
136	            if ((int) $order->version !== $expectedVersion) {
137	                return response()->json([
138	                    'message' => 'Version conflict: order was modified by another user.',
139	                    'error_code' => 'STALE_VERSION',
140	                    'current_version' => (int) $order->version,
141	                ], 409);
142	            }
143	
144	            $newTotal = round((float) $order->subtotal + (float) $order->tax - $amount, 2);
145	            $newVersion = (int) $order->version + 1;
146	
147	            $affected = DB::table('orders')
148	                ->where('id', $orderId)
149	                ->where('version', $expectedVersion)
150	                ->update([
151	                    'discount' => $amount,
152	                    'total' => max(0, $newTotal),
153	                    'version' => $newVersion,
154	                    'updated_at' => now(),
155	                ]);
156	
157	            if ($affected === 0) {
158	                return response()->json([
159	                    'message' => 'Version conflict: order was modified by another user.',
160	                    'error_code' => 'STALE_VERSION',
161	                ], 409);
162	            }
163	
164	            DB::table('privilege_escalation_logs')->insert([
165	                'action' => 'discount_override',
166	                'order_id' => $orderId,
167	                'manager_id' => $user->id,
168	                'manager_pin_hash' => $user->manager_pin,
169	                'reason' => $request->input('reason', "Manual discount of \${$amount}"),
170	                'metadata' => json_encode([
171	                    'discount_amount' => $amount,
172	                    'original_total' => (float) $order->total,
173	                    'new_total' => max(0, $newTotal),
174	                ]),
175	                'created_at' => now(),
176	            ]);
177	
178	            return response()->json([
179	                'data' => (array) DB::table('orders')->find($orderId),
180	            ]);
181	        });
182	    }
183	}
