5	namespace App\Application\Cart;
6	
7	use App\Application\Analytics\TrackEventUseCase;
8	use App\Domain\Cart\CartValidator;
9	use App\Domain\Cart\TaxCalculator;
10	use App\Domain\Risk\CaptchaTriggerEvaluator;
11	use Illuminate\Support\Facades\Cache;
12	use Illuminate\Support\Facades\Crypt;
13	use Illuminate\Support\Facades\DB;
14	
15	class CartService
16	{
17	    public function getOrCreateCart(string $sessionId, ?int $fingerprintId = null): object
18	    {
19	        $cart = DB::table('carts')->where('session_id', $sessionId)->first();
20	
21	        if (!$cart) {
22	            $cartId = DB::table('carts')->insertGetId([
23	                'session_id' => $sessionId,
24	                'device_fingerprint_id' => $fingerprintId,
25	                'created_at' => now(),
26	                'updated_at' => now(),
27	            ]);
28	            $cart = DB::table('carts')->find($cartId);
29	        }
30	
31	        return $cart;
32	    }
33	
34	    public function getCart(string $sessionId): ?object
35	    {
36	        return DB::table('carts')->where('session_id', $sessionId)->first();
37	    }
38	
39	    public function addItem(string $sessionId, int $menuItemId, ?int $fingerprintId = null): array
40	    {
41	        $menuItem = DB::table('menu_items')
42	            ->where('id', $menuItemId)
43	            ->where('is_active', true)
44	            ->first();
45	
46	        if (!$menuItem) {
47	            return ['error' => 'This item is no longer available.'];
48	        }
49	
50	        $cart = $this->getOrCreateCart($sessionId, $fingerprintId);
51	
52	        $existing = DB::table('cart_items')
53	            ->where('cart_id', $cart->id)
54	            ->where('menu_item_id', $menuItemId)
55	            ->first();
56	
57	        if ($existing) {
58	            $validator = new CartValidator();
59	            $newQuantity = $existing->quantity + 1;
60	            $errors = $validator->validateQuantity($newQuantity);
61	            if (!empty($errors)) {
62	                return ['error' => $errors[0]];
63	            }
64	            DB::table('cart_items')
65	                ->where('id', $existing->id)
66	                ->update(['quantity' => $newQuantity, 'updated_at' => now()]);
67	        } else {
68	            DB::table('cart_items')->insert([
69	                'cart_id' => $cart->id,
70	                'menu_item_id' => $menuItemId,
71	                'quantity' => 1,
72	                'flavor_preference' => null,
73	                'note' => null,
74	                'unit_price_snapshot' => $menuItem->price,
75	                'created_at' => now(),
76	                'updated_at' => now(),
77	            ]);
78	        }
79	
80	        // Track analytics event
81	        (new TrackEventUseCase())->execute(
82	            eventType: 'add_to_cart',
83	            sessionId: $sessionId,
84	            payload: ['menu_item_id' => $menuItemId, 'price' => (float) $menuItem->price],
85	        );
86	
87	        return ['success' => true];
88	    }
89	
90	    public function updateQuantity(int $cartItemId, int $cartId, int $quantity): array
91	    {
92	        $validator = new CartValidator();
93	        $errors = $validator->validateQuantity($quantity);
94	        if (!empty($errors)) {
95	            return ['error' => $errors[0]];
96	        }
97	
98	        DB::table('cart_items')
99	            ->where('id', $cartItemId)
100	            ->where('cart_id', $cartId)
101	            ->update(['quantity' => $quantity, 'updated_at' => now()]);
102	
103	        return ['success' => true];
104	    }
105	
106	    public function updateNote(int $cartItemId, int $cartId, string $note): array
107	    {
108	        $validator = new CartValidator();
109	        $errors = $validator->validateNote($note);
110	        if (!empty($errors)) {
111	            return ['error' => $errors[0]];
112	        }
113	
114	        $encryptedNote = $note !== '' ? Crypt::encryptString($note) : null;
115	
116	        DB::table('cart_items')
117	            ->where('id', $cartItemId)
118	            ->where('cart_id', $cartId)
119	            ->update(['note' => $encryptedNote, 'updated_at' => now()]);
120	
121	        return ['success' => true];
122	    }
123	
124	    public function updateFlavor(int $cartItemId, int $cartId, string $flavor): void
125	    {
126	        DB::table('cart_items')
127	            ->where('id', $cartItemId)
128	            ->where('cart_id', $cartId)
129	            ->update(['flavor_preference' => $flavor, 'updated_at' => now()]);
130	    }
131	
132	    public function removeItem(int $cartItemId, int $cartId): void
133	    {
134	        DB::table('cart_items')
135	            ->where('id', $cartItemId)
136	            ->where('cart_id', $cartId)
137	            ->delete();
138	    }
