140	    public function clearCart(int $cartId): void
141	    {
142	        DB::table('cart_items')->where('cart_id', $cartId)->delete();
143	    }
144	
145	    /**
146	     * Load cart items with enriched data (decrypted notes, prices, tax).
147	     *
148	     * @return array{items: array, subtotal: float, tax: float, total: float, taxBreakdown: array, priceChanges: array}
149	     */
150	    public function loadCartDetails(string $sessionId): array
151	    {
152	        $cart = $this->getCart($sessionId);
153	        $empty = ['items' => [], 'subtotal' => 0, 'tax' => 0, 'total' => 0, 'taxBreakdown' => [], 'priceChanges' => []];
154	
155	        if (!$cart) {
156	            return $empty;
157	        }
158	
159	        $items = DB::table('cart_items')
160	            ->join('menu_items', 'cart_items.menu_item_id', '=', 'menu_items.id')
161	            ->where('cart_items.cart_id', $cart->id)
162	            ->select([
163	                'cart_items.id',
164	                'cart_items.menu_item_id',
165	                'cart_items.quantity',
166	                'cart_items.flavor_preference',
167	                'cart_items.note',
168	                'cart_items.unit_price_snapshot',
169	                'menu_items.name',
170	                'menu_items.price as current_price',
171	                'menu_items.tax_category',
172	                'menu_items.sku',
173	                'menu_items.is_active',
174	            ])
175	            ->get();
176	
177	        $cartItems = [];
178	        $taxItems = [];
179	        $priceChanges = [];
180	
181	        foreach ($items as $item) {
182	            $priceChanged = abs((float) $item->unit_price_snapshot - (float) $item->current_price) > 0.001;
183	            if ($priceChanged) {
184	                $priceChanges[$item->id] = [
185	                    'old' => (float) $item->unit_price_snapshot,
186	                    'new' => (float) $item->current_price,
187	                ];
188	            }
189	
190	            $decryptedNote = null;
191	            if ($item->note) {
192	                try {
193	                    $decryptedNote = Crypt::decryptString($item->note);
194	                } catch (\Throwable) {
195	                    $decryptedNote = $item->note;
196	                }
197	            }
198	
199	            $cartItems[] = [
200	                'id' => $item->id,
201	                'menu_item_id' => $item->menu_item_id,
202	                'name' => $item->name,
203	                'sku' => $item->sku,
204	                'quantity' => $item->quantity,
205	                'unit_price' => (float) $item->unit_price_snapshot,
206	                'current_price' => (float) $item->current_price,
207	                'line_total' => round((float) $item->unit_price_snapshot * $item->quantity, 2),
208	                'flavor_preference' => $item->flavor_preference,
209	                'note' => $decryptedNote,
210	                'tax_category' => $item->tax_category,
211	                'is_active' => (bool) $item->is_active,
212	                'price_changed' => $priceChanged,
213	            ];
214	
215	            $taxItems[] = [
216	                'name' => $item->name,
217	                'price' => (float) $item->unit_price_snapshot,
218	                'quantity' => $item->quantity,
219	                'tax_category' => $item->tax_category,
220	            ];
221	        }
222	
223	        $subtotal = round(array_sum(array_column($cartItems, 'line_total')), 2);
224	
225	        $taxRules = DB::table('tax_rules')
226	            ->whereDate('effective_from', '<=', now())
227	            ->where(function ($q) {
228	                $q->whereNull('effective_to')->orWhereDate('effective_to', '>=', now());
229	            })
230	            ->get(['category', 'rate'])
231	            ->map(fn ($r) => (array) $r)
232	            ->toArray();
233	
234	        $calculator = new TaxCalculator($taxRules);
235	        $tax = $calculator->calculateCartTax($taxItems);
236	        $taxBreakdown = $calculator->getBreakdown($taxItems);
237	        $total = round($subtotal + $tax, 2);
238	
239	        // Track every cart summary recomputation as a repricing event for CAPTCHA trigger.
240	        // This captures rapid bot-like polling regardless of whether prices actually changed.
241	        $this->recordRepricingEvent($sessionId);
242	
243	        return [
244	            'items' => $cartItems,
245	            'subtotal' => $subtotal,
246	            'tax' => $tax,
247	            'total' => $total,
248	            'taxBreakdown' => $taxBreakdown,
249	            'priceChanges' => $priceChanges,
250	        ];
251	    }
252	
253	    /**
254	     * Record a repricing event timestamp for this session (for CAPTCHA evaluation).
255	     */
256	    public function recordRepricingEvent(string $sessionId): void
257	    {
258	        $cacheKey = "repricing_events:{$sessionId}";
259	        $timestamps = Cache::get($cacheKey, []);
260	        $timestamps[] = time();
261	
262	        // Keep only events within the last 5 minutes to prevent unbounded growth
263	        $cutoff = time() - 300;
264	        $timestamps = array_values(array_filter($timestamps, fn (int $ts) => $ts >= $cutoff));
265	
266	        Cache::put($cacheKey, $timestamps, now()->addMinutes(5));
267	    }
268	
269	    /**
270	     * Check whether rapid repricing CAPTCHA should be triggered for this session.
271	     */
272	    public function requiresRepricingCaptcha(string $sessionId): bool
273	    {
274	        $cacheKey = "repricing_events:{$sessionId}";
275	        $timestamps = Cache::get($cacheKey, []);
276	
277	        if (empty($timestamps)) {
278	            return false;
279	        }
280	
281	        $evaluator = app(CaptchaTriggerEvaluator::class);
282	        return $evaluator->shouldTriggerForRapidRepricing($timestamps);
283	    }
284	}
