5	namespace App\Domain\Risk;
6	
7	class CaptchaTriggerEvaluator
8	{
9	    public function __construct(
10	        private readonly int $failedLoginThreshold = 5,
11	        private readonly int $rapidRepricingThreshold = 3,
12	        private readonly int $rapidRepricingWindowSeconds = 60,
13	    ) {}
14	
15	    /**
16	     * Check if CAPTCHA should be triggered based on failed login count.
17	     */
18	    public function shouldTriggerForFailedLogins(int $failedCount): bool
19	    {
20	        return $failedCount >= $this->failedLoginThreshold;
21	    }
22	
23	    /**
24	     * Check if CAPTCHA should be triggered based on rapid re-pricing events.
25	     *
26	     * @param array $timestamps Unix timestamps of recent re-pricing events
27	     */
28	    public function shouldTriggerForRapidRepricing(array $timestamps): bool
29	    {
30	        if (count($timestamps) < $this->rapidRepricingThreshold) {
31	            return false;
32	        }
33	
34	        // Sort descending to check most recent events
35	        rsort($timestamps);
36	
37	        // Check if the threshold number of events occurred within the window
38	        $windowStart = $timestamps[0] - $this->rapidRepricingWindowSeconds;
39	        $eventsInWindow = 0;
40	
41	        foreach ($timestamps as $ts) {
42	            if ($ts >= $windowStart) {
43	                $eventsInWindow++;
44	            }
45	        }
46	
47	        return $eventsInWindow >= $this->rapidRepricingThreshold;
48	    }
49	
50	    public function getFailedLoginThreshold(): int
51	    {
52	        return $this->failedLoginThreshold;
53	    }
54	
55	    public function getRapidRepricingThreshold(): int
56	    {
57	        return $this->rapidRepricingThreshold;
58	    }
59	}
