11	class RoleMiddleware
12	{
13	    public function handle(Request $request, Closure $next, string ...$roles): Response
14	    {
15	        if (!$request->user()) {
16	            if ($request->expectsJson()) {
17	                return response()->json([
18	                    'message' => 'Authentication required.',
19	                    'error_code' => 'UNAUTHENTICATED',
20	                ], 401);
21	            }
22	
23	            return redirect()->guest(route('login'));
24	        }
25	
26	        $userRole = $request->user()->role;
27	
28	        if (!in_array($userRole, $roles, true)) {
29	            if ($request->expectsJson()) {
30	                return response()->json([
31	                    'message' => 'Access denied.',
32	                    'error_code' => 'FORBIDDEN',
33	                ], 403);
34	            }
35	
36	            abort(403, 'Access denied.');
37	        }
38	
39	        return $next($request);
40	    }
41	}
