232	    private function loadCartSummary(): void
233	    {
234	        // Read cart via REST API
235	        $api = app(InternalApiDispatcher::class);
236	        $result = $api->get('/cart');
237	        $body = $result['body'];
238	
239	        $items = $body['items'] ?? [];
240	
241	        if (empty($items)) {
242	            $this->cartSummary = null;
243	            return;
244	        }
245	
246	        $subtotal = 0;
247	        $itemList = [];
248	        $promoItems = [];
249	
250	        foreach ($items as $item) {
251	            $lineTotal = (float) ($item['line_total'] ?? round(($item['unit_price'] ?? 0) * ($item['quantity'] ?? 0), 2));
252	            $subtotal += $lineTotal;
253	            $itemList[] = [
254	                'name' => $item['name'] ?? '',
255	                'sku' => $item['sku'] ?? '',
256	                'quantity' => $item['quantity'] ?? 0,
257	                'unit_price' => (float) ($item['unit_price'] ?? 0),
258	                'line_total' => $lineTotal,
