263	                'quantity' => $item['quantity'] ?? 0,
264	                'name' => $item['name'] ?? '',
265	            ];
266	        }
267	
268	        $subtotal = round($subtotal, 2);
269	
270	        // Evaluate promotions (domain logic via service — not a mutation)
271	        $this->appliedPromotion = null;
272	        $promotions = DB::table('promotions')
273	            ->where('is_active', true)
274	            ->where('starts_at', '<=', now())
275	            ->where('ends_at', '>=', now())
276	            ->get()
277	            ->map(function ($p) {
