281	            })
282	            ->toArray();
283	
284	        if (!empty($promotions)) {
285	            $evaluator = app(PromotionEvaluator::class);
286	            $this->appliedPromotion = $evaluator->evaluate($promoItems, $promotions, $subtotal);
287	
288	            if ($this->appliedPromotion) {
289	                $localTz = config('harborbite.timezone', 'America/Chicago');
290	                $matchedPromo = collect($promotions)->firstWhere('id', $this->appliedPromotion['promotion_id']);
291	                if ($matchedPromo) {
