94	        $ipKey = "failed_logins:ip:{$ip}";
95	        Cache::put($deviceKey, (int) Cache::get($deviceKey, 0) + 1, now()->addHour());
96	        Cache::put($ipKey, (int) Cache::get($ipKey, 0) + 1, now()->addHour());
