12	     * Returns an array of exclusion rules used to filter out items
13	     * based on their JSONB `attributes` column.
14	     *
15	     * @param array $filters e.g. ['nuts', 'gluten', 'dairy', 'shellfish', 'spicy']
16	     * @return array Array of exclusion rules
17	     */
18	    public function buildExclusions(array $filters): array
19	    {
20	        $exclusions = [];
21	
22	        foreach ($filters as $filter) {
23	            $filter = strtolower(trim($filter));
24	
25	            switch ($filter) {
26	                case 'nuts':
27	                    // Exclude items where contains_nuts = true
28	                    $exclusions[] = ['key' => 'contains_nuts', 'exclude_when' => true];
29	                    break;
30	
31	                case 'gluten':
32	                    // Exclude items where gluten_free = false (contains gluten)
33	                    $exclusions[] = ['key' => 'gluten_free', 'exclude_when' => false];
34	                    break;
35	
36	                case 'dairy':
37	                    // Exclude items where contains_dairy = true
38	                    $exclusions[] = ['key' => 'contains_dairy', 'exclude_when' => true];
39	                    break;
40	
41	                case 'shellfish':
42	                    // Exclude items where contains_shellfish = true
43	                    $exclusions[] = ['key' => 'contains_shellfish', 'exclude_when' => true];
44	                    break;
45	
46	                case 'vegan':
47	                    // Show only vegan: exclude where is_vegan = false
48	                    $exclusions[] = ['key' => 'is_vegan', 'exclude_when' => false];
49	                    break;
50	
51	                case 'spicy':
52	                    // Exclude spicy items: exclude where spicy_level > 0
53	                    $exclusions[] = ['key' => 'spicy_level', 'exclude_when_gt' => 0];
