19	    /**
20	     * Check if a query contains banned words.
21	     *
22	     * @return array{blocked: bool, matched_word: string|null, message: string|null}
23	     */
24	    public function check(string $query): array
25	    {
26	        $queryLower = strtolower(trim($query));
27	
28	        if (empty($queryLower)) {
29	            return ['blocked' => false, 'matched_word' => null, 'message' => null];
30	        }
31	
32	        $queryWords = preg_split('/\s+/', $queryLower);
33	
34	        foreach ($this->bannedWords as $banned) {
35	            // Check exact word match
36	            if (in_array($banned, $queryWords, true)) {
37	                return [
38	                    'blocked' => true,
39	                    'matched_word' => $banned,
40	                    'message' => 'This search term is not allowed. Please try a different search.',
41	                ];
42	            }
43	
44	            // Check if query contains banned word as substring
45	            if (str_contains($queryLower, $banned)) {
46	                return [
47	                    'blocked' => true,
48	                    'matched_word' => $banned,
49	                    'message' => 'This search term is not allowed. Please try a different search.',
50	                ];
51	            }
52	        }
53	
