153	        $empty = ['items' => [], 'subtotal' => 0, 'tax' => 0, 'total' => 0, 'taxBreakdown' => [], 'priceChanges' => []];
154	
155	        if (!$cart) {
156	            return $empty;
157	        }
158	
159	        $items = DB::table('cart_items')
160	            ->join('menu_items', 'cart_items.menu_item_id', '=', 'menu_items.id')
161	            ->where('cart_items.cart_id', $cart->id)
162	            ->select([
163	                'cart_items.id',
164	                'cart_items.menu_item_id',
165	                'cart_items.quantity',
166	                'cart_items.flavor_preference',
167	                'cart_items.note',
168	                'cart_items.unit_price_snapshot',
169	                'menu_items.name',
