171	                'menu_items.tax_category',
172	                'menu_items.sku',
173	                'menu_items.is_active',
174	            ])
175	            ->get();
176	
177	        $cartItems = [];
178	        $taxItems = [];
179	        $priceChanges = [];
180	
181	        foreach ($items as $item) {
182	            $priceChanged = abs((float) $item->unit_price_snapshot - (float) $item->current_price) > 0.001;
183	            if ($priceChanged) {
184	                $priceChanges[$item->id] = [
185	                    'old' => (float) $item->unit_price_snapshot,
186	                    'new' => (float) $item->current_price,
187	                ];
188	            }
189	
190	            $decryptedNote = null;
191	            if ($item->note) {
192	                try {
