194	                } catch (\Throwable) {
195	                    $decryptedNote = $item->note;
196	                }
197	            }
198	
199	            $cartItems[] = [
200	                'id' => $item->id,
201	                'menu_item_id' => $item->menu_item_id,
202	                'name' => $item->name,
203	                'sku' => $item->sku,
204	                'quantity' => $item->quantity,
205	                'unit_price' => (float) $item->unit_price_snapshot,
206	                'current_price' => (float) $item->current_price,
