270	     */
271	    public function recordRepricingEvent(string $sessionId): void
272	    {
273	        $cacheKey = "repricing_events:{$sessionId}";
274	        $timestamps = Cache::get($cacheKey, []);
275	        $timestamps[] = time();
276	
277	        // Keep only events within the last 5 minutes to prevent unbounded growth
278	        $cutoff = time() - 300;
279	        $timestamps = array_values(array_filter($timestamps, fn (int $ts) => $ts >= $cutoff));
280	
281	        Cache::put($cacheKey, $timestamps, now()->addMinutes(5));
282	    }
