12	
13	class RateLimitMiddleware
14	{
15	    public function handle(Request $request, Closure $next, string $action = 'general', int $maxAttempts = 0, int $windowMinutes = 0): Response
16	    {
17	        // Always resolve from config by action key; explicit params override config values.
18	        $configLimits = match ($action) {
19	            'registration' => [
20	                'max' => (int) config('harborbite.rate_limits.registrations_per_hour', 10),
21	                'window' => 60,
22	            ],
23	            'checkout' => [
24	                'max' => (int) config('harborbite.rate_limits.checkouts_per_10_min', 30),
25	                'window' => 10,
26	            ],
27	            'login' => [
28	                'max' => 10,
29	                'window' => 1,
30	            ],
31	            default => [
32	                'max' => (int) config('harborbite.rate_limits.general_per_minute', 60),
33	                'window' => 1,
34	            ],
35	        };
36	
37	        $maxAttempts = $maxAttempts > 0 ? $maxAttempts : $configLimits['max'];
38	        $windowMinutes = $windowMinutes > 0 ? $windowMinutes : $configLimits['window'];
39	
40	        // Check whitelist first (device, IP CIDR, or username)
41	        $fingerprintHash = $request->attributes->get('device_fingerprint_hash');
42	        if ($fingerprintHash && $this->isWhitelisted('device', $fingerprintHash)) {
43	            return $next($request);
44	        }
45	        if ($request->ip() && $this->isWhitelisted('ip', $request->ip())) {
46	            return $next($request);
47	        }
48	        $username = $request->input('username') ?? auth()->user()?->username ?? null;
49	        if ($username && $this->isUsernameWhitelisted($username)) {
50	            return $next($request);
51	        }
52	
53	        // Per-device rate limit
54	        if ($fingerprintHash) {
55	            $deviceKey = "rate_limit:device:{$action}:{$fingerprintHash}";
56	            $deviceCount = (int) Cache::get($deviceKey, 0);
57	
58	            if ($deviceCount >= $maxAttempts) {
59	                $this->logRateLimit($request, 'device', $action);
60	                return $this->tooManyRequestsResponse($windowMinutes);
61	            }
62	
63	            Cache::put($deviceKey, $deviceCount + 1, now()->addMinutes($windowMinutes));
64	        }
65	
66	        // Per-IP rate limit
67	        $ip = $request->ip();
68	        if ($ip) {
69	            $ipKey = "rate_limit:ip:{$action}:{$ip}";
70	            $ipCount = (int) Cache::get($ipKey, 0);
71	
72	            if ($ipCount >= $maxAttempts) {
73	                $this->logRateLimit($request, 'ip', $action);
74	                return $this->tooManyRequestsResponse($windowMinutes);
75	            }
76	
77	            Cache::put($ipKey, $ipCount + 1, now()->addMinutes($windowMinutes));
78	        }
79	
80	        return $next($request);
81	    }
82	
83	    private function isWhitelisted(string $type, string $value): bool
84	    {
85	        if ($type === 'ip') {
86	            return $this->isIpWhitelisted($value);
87	        }
88	
89	        return DB::table('security_whitelists')
90	            ->where('type', $type)
91	            ->where('value', $value)
92	            ->exists();
93	    }
94	
95	    private function isUsernameWhitelisted(string $username): bool
96	    {
97	        return DB::table('security_whitelists')
98	            ->where('type', 'username')
99	            ->where('value', $username)
100	            ->exists();
101	    }
102	
103	    private function isIpWhitelisted(string $ip): bool
104	    {
105	        $entries = DB::table('security_whitelists')
106	            ->where('type', 'ip')
107	            ->pluck('value');
108	
109	        foreach ($entries as $entry) {
110	            if ($this->ipMatchesCidr($ip, $entry)) {
111	                return true;
112	            }
113	        }
114	
115	        return false;
116	    }
117	
118	    private function ipMatchesCidr(string $ip, string $cidr): bool
119	    {
120	        if (!str_contains($cidr, '/')) {
121	            return $ip === $cidr;
122	        }
123	
124	        [$subnet, $mask] = explode('/', $cidr);
