5	namespace App\Infrastructure\Api;
6	
7	use Illuminate\Http\Request;
8	use Illuminate\Support\Facades\Route;
9	
10	/**
11	 * Dispatches internal requests through the Laravel router so that
12	 * Livewire components consume the same REST API endpoints as external
13	 * clients — maintaining a single authoritative write path.
14	 */
15	class InternalApiDispatcher
16	{
17	    public function get(string $uri, array $query = []): array
18	    {
19	        return $this->dispatch('GET', $uri, $query);
20	    }
21	
22	    public function post(string $uri, array $data = []): array
23	    {
24	        return $this->dispatch('POST', $uri, $data);
25	    }
26	
27	    public function patch(string $uri, array $data = []): array
28	    {
29	        return $this->dispatch('PATCH', $uri, $data);
30	    }
31	
32	    public function delete(string $uri, array $data = []): array
33	    {
34	        return $this->dispatch('DELETE', $uri, $data);
35	    }
36	
37	    private function dispatch(string $method, string $uri, array $data): array
38	    {
39	        $fullUri = '/api' . $uri;
40	
41	        $request = Request::create($fullUri, $method, $data);
42	
43	        // Carry forward session, auth, and fingerprint from parent request
44	        $parentRequest = app('request');
45	
46	        if ($parentRequest->hasSession()) {
47	            $request->setLaravelSession($parentRequest->session());
48	        }
49	
50	        $request->headers->set('X-Session-Id', session()->getId());
51	
52	        // Forward device fingerprint attributes
53	        $request->attributes->set(
54	            'device_fingerprint_id',
55	            $parentRequest->attributes->get('device_fingerprint_id'),
56	        );
57	        $request->attributes->set(
58	            'device_fingerprint_hash',
59	            $parentRequest->attributes->get('device_fingerprint_hash'),
60	        );
61	
62	        // Forward auth
63	        if (auth()->check()) {
64	            $user = auth()->user();
65	            $request->setUserResolver(fn () => $user);
66	        }
67	
68	        $response = Route::dispatch($request);
69	
70	        return [
71	            'status' => $response->getStatusCode(),
72	            'body' => json_decode($response->getContent(), true) ?? [],
73	        ];
74	    }
75	}
