1	<?php
2	
3	use Illuminate\Support\Facades\DB;
4	use Livewire\Livewire;
5	use App\Livewire\Cart\CartManager;
6	
7	beforeEach(function () {
8	    // Seed menu categories
9	    DB::table('menu_categories')->insert([
10	        ['id' => 1, 'name' => 'Hot Food', 'sort_order' => 1, 'is_active' => true, 'created_at' => now(), 'updated_at' => now()],
11	        ['id' => 2, 'name' => 'Cold Food', 'sort_order' => 2, 'is_active' => true, 'created_at' => now(), 'updated_at' => now()],
12	    ]);
13	
14	    // Seed menu items with different tax categories
15	    DB::table('menu_items')->insert([
16	        ['id' => 1, 'sku' => 'HOT-001', 'menu_category_id' => 1, 'name' => 'Grilled Burger', 'description' => 'Hot prepared burger', 'price' => 12.99, 'tax_category' => 'hot_prepared', 'is_active' => true, 'attributes' => '{}', 'created_at' => now(), 'updated_at' => now()],
17	        ['id' => 2, 'sku' => 'COLD-001', 'menu_category_id' => 2, 'name' => 'Caesar Salad', 'description' => 'Cold prepared salad', 'price' => 9.99, 'tax_category' => 'cold_prepared', 'is_active' => true, 'attributes' => '{}', 'created_at' => now(), 'updated_at' => now()],
18	        ['id' => 3, 'sku' => 'HOT-002', 'menu_category_id' => 1, 'name' => 'Fish & Chips', 'description' => 'Hot prepared fish', 'price' => 14.50, 'tax_category' => 'hot_prepared', 'is_active' => true, 'attributes' => '{}', 'created_at' => now(), 'updated_at' => now()],
19	    ]);
20	
21	    // Seed tax rules with different rates for hot and cold
22	    DB::table('tax_rules')->insert([
23	        ['category' => 'hot_prepared', 'rate' => 0.0825, 'effective_from' => '2025-01-01', 'effective_to' => null, 'created_at' => now(), 'updated_at' => now()],
24	        ['category' => 'cold_prepared', 'rate' => 0.0625, 'effective_from' => '2025-01-01', 'effective_to' => null, 'created_at' => now(), 'updated_at' => now()],
25	    ]);
26	
27	    if (DB::getDriverName() === 'pgsql') {
28	        DB::statement("SELECT setval('menu_categories_id_seq', (SELECT MAX(id) FROM menu_categories))");
29	        DB::statement("SELECT setval('menu_items_id_seq', (SELECT MAX(id) FROM menu_items))");
30	    }
31	});
32	
33	test('hot food item gets correct tax rate applied', function () {
34	    $component = Livewire::test(CartManager::class)
35	        ->call('addItem', 1); // Grilled Burger, hot_prepared @ 12.99
36	
37	    $component->assertSet('hasItems', true);
38	
39	    $expectedTax = round(12.99 * 1 * 0.0825, 2); // 1.07
40	    $component->assertSet('tax', $expectedTax);
41	    $component->assertSet('subtotal', 12.99);
42	    $component->assertSet('total', round(12.99 + $expectedTax, 2));
43	});
44	
45	test('cold food item gets different tax rate applied', function () {
46	    $component = Livewire::test(CartManager::class)
47	        ->call('addItem', 2); // Caesar Salad, cold_prepared @ 9.99
48	
49	    $component->assertSet('hasItems', true);
50	
51	    $expectedTax = round(9.99 * 1 * 0.0625, 2); // 0.62
52	    $component->assertSet('tax', $expectedTax);
53	    $component->assertSet('subtotal', 9.99);
54	    $component->assertSet('total', round(9.99 + $expectedTax, 2));
55	});
56	
57	test('mixed cart calculates per-item tax correctly', function () {
58	    $component = Livewire::test(CartManager::class)
59	        ->call('addItem', 1)  // Grilled Burger, hot_prepared @ 12.99
60	        ->call('addItem', 2); // Caesar Salad, cold_prepared @ 9.99
61	
62	    $hotTax = round(12.99 * 1 * 0.0825, 2);  // 1.07
63	    $coldTax = round(9.99 * 1 * 0.0625, 2);  // 0.62
64	    $expectedTax = round($hotTax + $coldTax, 2); // 1.69
65	
66	    $component->assertSet('subtotal', round(12.99 + 9.99, 2));
67	    $component->assertSet('tax', $expectedTax);
68	    $component->assertSet('total', round(12.99 + 9.99 + $expectedTax, 2));
69	});
70	
71	test('tax breakdown contains per-item details', function () {
72	    $component = Livewire::test(CartManager::class)
73	        ->call('addItem', 1)  // hot_prepared
74	        ->call('addItem', 2); // cold_prepared
75	
76	    $breakdown = $component->get('taxBreakdown');
77	
78	    expect($breakdown)->toHaveCount(2);
79	    expect($breakdown[0]['tax_category'])->toBe('hot_prepared');
80	    expect($breakdown[0]['rate'])->toBe(0.0825);
81	    expect($breakdown[1]['tax_category'])->toBe('cold_prepared');
82	    expect($breakdown[1]['rate'])->toBe(0.0625);
83	});
84	
85	test('increasing quantity recalculates tax correctly', function () {
86	    $component = Livewire::test(CartManager::class)
87	        ->call('addItem', 1); // Grilled Burger x1
88	
89	    $cartItemId = $component->get('cartItems.0.id');
90	
91	    $component->call('updateQuantity', $cartItemId, 3); // Burger x3
92	
93	    $expectedTax = round(12.99 * 3 * 0.0825, 2); // 3.22
94	    $component->assertSet('tax', $expectedTax);
95	    $component->assertSet('subtotal', round(12.99 * 3, 2));
96	});
97	
98	test('multiple hot items sum taxes from same category', function () {
99	    $component = Livewire::test(CartManager::class)
100	        ->call('addItem', 1)  // Grilled Burger, hot_prepared @ 12.99
101	        ->call('addItem', 3); // Fish & Chips, hot_prepared @ 14.50
102	
103	    $burgerTax = round(12.99 * 1 * 0.0825, 2);  // 1.07
104	    $fishTax = round(14.50 * 1 * 0.0825, 2);    // 1.20
105	    $expectedTax = round($burgerTax + $fishTax, 2); // 2.27
106	
107	    $component->assertSet('tax', $expectedTax);
108	});
109	
110	test('empty cart has zero tax', function () {
111	    $component = Livewire::test(CartManager::class);
112	
113	    $component->assertSet('tax', 0);
114	    $component->assertSet('subtotal', 0);
115	    $component->assertSet('total', 0);
116	    $component->assertSet('hasItems', false);
117	});
118	
119	test('removing item recalculates tax', function () {
120	    $component = Livewire::test(CartManager::class)
121	        ->call('addItem', 1)  // hot
122	        ->call('addItem', 2); // cold
123	
124	    $cartItems = $component->get('cartItems');
125	    $coldItemId = $cartItems[1]['id'];
126	
127	    $component->call('removeItem', $coldItemId);
128	
129	    // Only hot item remains
130	    $expectedTax = round(12.99 * 1 * 0.0825, 2);
131	    $component->assertSet('tax', $expectedTax);
132	    $component->assertSet('subtotal', 12.99);
133	});
134	
