1	<?php
2	
3	declare(strict_types=1);
4	
5	namespace App\Livewire\Cart;
6	
7	use App\Infrastructure\Api\InternalApiDispatcher;
8	use Livewire\Component;
9	
10	class CartManager extends Component
11	{
12	    public array $cartItems = [];
13	    public float $subtotal = 0;
14	    public float $tax = 0;
15	    public float $total = 0;
16	    public array $taxBreakdown = [];
17	    public bool $hasItems = false;
18	    public array $priceChanges = [];
19	
20	    protected $listeners = ['add-to-cart' => 'addItem', 'cart-refresh' => '$refresh'];
21	
22	    public function mount(): void
23	    {
24	        $this->loadCart();
25	    }
26	
27	    public function addItem(int $itemId): void
28	    {
29	        $api = app(InternalApiDispatcher::class);
30	        $result = $api->post('/cart/items', ['menu_item_id' => $itemId]);
31	
32	        if ($result['status'] >= 400) {
33	            $this->dispatch('notify', type: 'error', message: $result['body']['message'] ?? 'Error adding item.');
34	            return;
35	        }
36	
37	        $this->loadCart();
38	        $this->dispatch('cart-updated', count: count($this->cartItems));
39	    }
40	
41	    public function updateQuantity(int $cartItemId, int $quantity): void
42	    {
43	        $api = app(InternalApiDispatcher::class);
44	        $result = $api->patch("/cart/items/{$cartItemId}", ['quantity' => $quantity]);
45	
46	        if ($result['status'] >= 400) {
47	            $this->dispatch('notify', type: 'error', message: $result['body']['message'] ?? 'Error updating quantity.');
48	            return;
49	        }
50	
51	        $this->loadCart();
52	        $this->dispatch('cart-updated', count: count($this->cartItems));
53	    }
54	
55	    public function updateNote(int $cartItemId, string $note): void
56	    {
57	        $api = app(InternalApiDispatcher::class);
58	        $result = $api->patch("/cart/items/{$cartItemId}", ['note' => $note]);
59	
60	        if ($result['status'] >= 400) {
61	            $this->dispatch('notify', type: 'error', message: $result['body']['message'] ?? 'Error updating note.');
62	            return;
63	        }
64	
65	        $this->loadCart();
66	    }
67	
68	    public function updateFlavor(int $cartItemId, string $flavor): void
69	    {
70	        $api = app(InternalApiDispatcher::class);
71	        $api->patch("/cart/items/{$cartItemId}", ['flavor_preference' => $flavor]);
72	        $this->loadCart();
73	    }
74	
75	    public function removeItem(int $cartItemId): void
76	    {
77	        $api = app(InternalApiDispatcher::class);
78	        $api->delete("/cart/items/{$cartItemId}");
79	        $this->loadCart();
80	        $this->dispatch('cart-updated', count: count($this->cartItems));
81	    }
82	
83	    public function clearCart(): void
84	    {
85	        $api = app(InternalApiDispatcher::class);
86	        $api->delete('/cart');
87	        $this->loadCart();
88	        $this->dispatch('cart-updated', count: 0);
89	    }
90	
91	    private function loadCart(): void
92	    {
93	        $api = app(InternalApiDispatcher::class);
94	        $result = $api->get('/cart');
95	        $body = $result['body'];
96	
97	        $this->cartItems = $body['items'] ?? [];
98	        $this->subtotal = (float) ($body['totals']['subtotal'] ?? 0);
99	        $this->tax = (float) ($body['totals']['tax'] ?? 0);
100	        $this->total = (float) ($body['totals']['total'] ?? 0);
101	        $this->taxBreakdown = $body['tax_breakdown'] ?? [];
102	        $this->priceChanges = $body['price_changes'] ?? [];
103	        $this->hasItems = !empty($this->cartItems);
104	    }
105	
106	    public function render()
107	    {
108	        return view('livewire.cart.cart-manager');
109	    }
110	}
